Create mcp-filesystem/src/bridge.js:
```javascript
import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { SSEServerTransport } from '@modelcontextprotocol/sdk/server/sse.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import express from 'express';
import { spawn } from 'child_process';

const app = express();
const PORT = process.env.PORT || 3001;
const ALLOWED_PATHS = process.env.ALLOWED_PATHS || '/config';

// Spawn server-filesystem as subprocess
const child = spawn('npx', [
  '@modelcontextprotocol/server-filesystem',
  ...ALLOWED_PATHS.split(',').map(p => p.trim())
]);

// Create SSE endpoint
const transport = new SSEServerTransport('/sse', app);
await transport.start();

// Pipe subprocess stdio to SSE transport
child.stdout.pipe(transport.stdin);
transport.stdout.pipe(child.stdin);

app.listen(PORT, '0.0.0.0', () => {
  console.log(`MCP Filesystem HTTP server on :${PORT}`);
});
```

